Int[x_^4/((d_+e_.*x_^2)*Sqrt[a_+c_.*x_^4]),x_Symbol] :=
  With[{q=Rt[c/a,2]},
  -1/(e*q) \[Star] Int[(1-q*x^2)/Sqrt[a+c*x^4],x] + 
  d^2/(e*(e-d*q)) \[Star] Int[(1+q*x^2)/((d+e*x^2)*Sqrt[a+c*x^4]),x] /;
 EqQ[2*c*d-a*e*q,0]] /;
FreeQ[{a,c,d,e},x] && PosQ[c/a] && NeQ[c*d^2-a*e^2,0]
